import anthropic

client = anthropic.Anthropic()

# Tool specifications for the Anthropic API
browser_tools = [
    {
        "name": "navigate",
        "description": "Navigate to a URL and return the page title and visible text.",
        "input_schema": {
            "type": "object",
            "properties": {
                "url": {"type": "string", "description": "The URL to navigate to"},
            },
            "required": ["url"],
        },
    },
    {
        "name": "click",
        "description": "Click an element on the current page using a CSS selector.",
        "input_schema": {
            "type": "object",
            "properties": {
                "selector": {"type": "string", "description": "CSS selector or text, e.g. 'button[type=submit]'"},
            },
            "required": ["selector"],
        },
    },
    {
        "name": "get_links",
        "description": "Return all hyperlinks on the current page.",
        "input_schema": {"type": "object", "properties": {}},
    },
]

def run_browser_agent(task: str) -> str:
    session = BrowserSession(headless=True)
    session.start()
    messages = [{"role": "user", "content": task}]
    system = (
        "You are a web automation agent. "
        "Use the browser tools to complete the user's task. "
        "Navigate to URLs, read the page content, and take actions. "
        "Call final_answer with your result when done."
    )
    try:
        while True:
            response = client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=1024,
                system=system,
                tools=browser_tools,
                messages=messages,
            )
            messages.append({"role": "assistant", "content": response.content})

            if response.stop_reason == "end_turn":
                # Extract final text response
                for block in response.content:
                    if hasattr(block, "text"):
                        return block.text
                return "Done."

            # Process tool calls
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    name = block.name
                    inputs = block.input
                    if name == "navigate":
                        result = session.navigate(inputs["url"])
                    elif name == "click":
                        result = session.click(inputs["selector"])
                    elif name == "get_links":
                        result = session.get_links()
                    else:
                        result = f"Unknown tool: {name}"
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })

            messages.append({"role": "user", "content": tool_results})
    finally:
        session.stop()

result = run_browser_agent("Go to example.com and tell me what the page says.")
print(result)
